<template>
  <div class="preOrder-wrap">
    <van-nav-bar
      title="确认订单"
      left-text="返回"
      left-arrow
      @click-left="$router.go(-1)"
    />
    <!-- <van-contact-card
      type="edit"
      :name="currentContact.name"
      :tel="currentContact.tel"
      @click="$router.push('/address/list')"
    /> -->
    <van-cell @click="getAddress" is-link class="aic pt-15 pb-15">
      <van-icon slot="icon" name="location-o" />
      <div class="info ml-10">
        <p>
          <span style="font-weight: bold">{{ currentContact.name }}</span>
          <span class="ml-5" style="color: #797d58">{{ currentContact.tel }}</span>
        </p>
        <p class="f14">{{ currentContact.address }}</p>
      </div>
    </van-cell>
    <van-card
      v-for="(item, index) in carts"
      :key="index"
      :num="item.buyNum"
      :price="item.price / 100"
      :desc="item.slaveName"
      :title="item.masterName"
      :thumb="item.imgUrl"
    />

    <van-cell-group>
      <van-cell title="商品总金额"
        ><span class="flex jc-e aic red"
          ><i class="iconfont icon-fl-renminbi"></i>{{ totalMoney }}</span
        ></van-cell
      >
      <van-cell title="运费"
        ><span class="flex jc-e aic red"
          ><i class="iconfont icon-fl-renminbi"></i>0</span
        ></van-cell
      >
    </van-cell-group>
    <van-cell-group class="mt-10">
      <van-cell is-link value="0张券可用">
        <div slot="title" class="flex aic">
          <van-icon size="18" color="red" name="comment-o" />
          <span class="ml-5">优惠券</span>
        </div>
      </van-cell>
      <van-cell is-link value="0张券可用">
        <div slot="title" class="flex aic">
          <van-icon size="18" color="red" name="comment-o" />
          <span class="ml-5">苏打券</span>
        </div>
      </van-cell>
      <van-cell is-link value="¥0.00" value-class="red">
        <div slot="title" class="flex aic">
          <van-icon size="18" color="red" name="gem-o" />
          <span class="ml-5">余额</span>
        </div>
      </van-cell>
      <van-cell is-link value="不开发票">
        <div slot="title" class="flex aic">
          <van-icon size="18" color="red" name="balance-list-o" />
          <span class="ml-5">发票</span>
        </div>
      </van-cell>
    </van-cell-group>
    <van-action-sheet
      @closed="$router.push('/order/detail/' + order.orderId)"
      v-model="show"
    >
      <div class="content">
        <van-radio-group v-model="payType">
          <van-cell>
            <van-icon
              class="f20"
              slot="title"
              color="green"
              name="wechat-pay"
            />
            <van-radio
              slot="right-icon"
              icon-size="16px"
              checked-color="red"
              name="wechat"
            ></van-radio>
          </van-cell>
          <van-cell>
            <van-icon class="f20" slot="title" color="blue" name="alipay" />
            <van-radio
              slot="right-icon"
              icon-size="16px"
              checked-color="red"
              name="alipay"
            ></van-radio>
          </van-cell>
        </van-radio-group>
        <van-button class="mt-30" @click="pay" type="danger" block
          >立即支付</van-button
        >
      </div>
    </van-action-sheet>
    <van-submit-bar
      :price="totalMoney * 100"
      button-text="提交订单"
      @submit="onSubmit"
    />
  </div>
</template>

<script>
import $axios from "@/utils/index";
export default {
  data() {
    return {
      currentContact: {},
      show: false,
      payType: "wechat",
      carts: null,
      totalMoney: 0,
      order: null,
    };
  },
  methods: {
    async onSubmit() {
      try {
        let data = {
          addressInfo: this.currentContact,
          allFee: this.totalMoney,
          discount: 0,
          preOrderId: this.$route.query.preOrderId,
        };
        // console.log(data)
        let res = await $axios.post("order/add", data);
        // console.log(res);
        this.order = res.result;
        this.show = !this.show;
      } catch (err) {
        console.log(err);
      }
    },
    async getOrderList() {
      try {
        let data = this.$route.query;
        let res = await $axios.get("preOrder/detail", data);
        // console.log(res)
        (this.carts = res.result.carts),
          (this.totalMoney = res.result.totalMoney);
      } catch (err) {
        console.log(err);
      }
    },
    async pay() {
      try {
        let data = {
          orderId: this.order.orderId,
          allFee: this.totalMoney,
        };
        let res = await $axios.post("order/pay", data);
        // console.log(res)
        let query = {
          totalMoney: this.totalMoney,
          qrCode: res.result.qrcode,
          createTime: this.order.createTime,
          orderId: this.order.orderId,
        };
        this.$router.push({
          name: "pay",
          query: query,
        });
      } catch (err) {
        console.log(err);
      }
    },
    getAddress() {
      this.$router.push({
        path: "/address/list",
        query: { preOrderId: this.$route.query.preOrderId },
      });
    },
    async getContactInfo() {
      if (!this.$route.query.address) {
        try {
          let res = await $axios.get("address/all");
          // console.log(res)
          let defaultAddr = res.list.find(
            (item) => item.isDefault === true
          );
          if(!defaultAddr) defaultAddr=res.list[0]
          defaultAddr.address =
            defaultAddr.province +
            defaultAddr.city +
            defaultAddr.county +
            defaultAddr.addressDetail;
          this.currentContact={
            name:defaultAddr.name,
            tel:defaultAddr.tel,
            address:defaultAddr.address
          }
        } catch (err) {
          console.log(err);
        } finally {
          return;
        }
      }
      this.currentContact = {
        name:this.$route.query.name,
        tel:this.$route.query.tel,
        address:this.$route.query.address
      };
    },
  },
  created() {
    this.getOrderList();
    this.getContactInfo();
  },
};
</script>

<style lang="less">
.preOrder-wrap {
  .van-card {
    margin-top: 1px;
    background-color: #fff;
  }
  .content {
    padding: 10px;
  }
}
</style>